INSERT INTO `wp_kboard_board_content` VALUES (1,1,0,0,'윤준석','테스트 입니다','공지사항 테스트 입니다','20260124060023','20260321074832',10,0,0,0,0,'/wp-content/uploads/kboard_thumbnails/1/202601/69745ff7ccc599554562.png','묵찌-로고.png','공지사항','','','','','','','1','trash','1234'),(2,1,0,3,'quevic','로그인 후 글쓰기 테스트','데스트 입니다','20260124060321','20260321074824',9,0,0,1,-1,'/wp-content/uploads/kboard_thumbnails/1/202601/697460a9b3e6c7992621.png','묵찌-로고.png','공지사항','','','','','','','1','trash',''),(7,1,0,0,'1234','1234','1234','20260228075018','20260321065916',7,0,0,0,0,'','','공지사항','','','','','','','1','trash','1234'),(8,1,0,0,'12345','12345','test','20260228075039','20260321065916',6,0,0,0,0,'','','','','','','','','','1','trash','12345'),(9,1,0,0,'22','22','22','20260228075056','20260321065916',5,0,0,0,0,'','','공지사항','','','','','','','1','trash','22'),(10,1,0,0,'44','44','44','20260228075116','20260321074814',10,0,1,0,1,'','','공지사항','','','','','','','1','trash','44'),(11,3,0,1,'gpchurch','테스트 일정','<p>테스트 일정</p>','20260228084255','20260314075608',8,0,0,0,0,'','','','','','','','','','1','trash',''),(12,3,0,0,'익명','테스트 일정2','<p>1234</p>','20260307065509','20260314075602',3,0,0,0,0,'','','','','','','','','','1','trash','1234'),(13,3,0,1,'gpchurch','일정 테스트','<p>ㅁㄴㅇㄹ</p>','20260314070921','20260314075718',1,0,0,0,0,'','','','','','','','','','1','trash',''),(19,3,0,1,'gpchurch','테스트22','<p>ㅇ</p>','20260314075625','20260321083015',2,0,0,0,0,'','','','','','','','','','1','trash',''),(20,3,0,1,'gpchurch','테스트33','<p>ㄴ</p>','20260314075648','20260321083020',2,0,0,0,0,'','','','','','','','','','1','trash',''),(21,3,0,1,'gpchurch','ㅇㅇ','<p>ㅇㅇ</p>','20260314075731','20260321083026',2,0,0,0,0,'','','','','','','','','','1','trash',''),(27,2,0,1,'관리자','2026.3.14 패스파인더 안식일 저녁 식사 교제','<p>2026년 3월 14일 안식일을 은혜롭게 마치고, 패스파인더 대원들과 함께 즐거운 저녁 식사 교제의 시간을 가졌습니다.</p>\n<p>맛있는 음식과 더불어 서로의 삶과 신앙을 나누며 화기애애한 웃음꽃이 피어난 행복한 안식일 저녁이었습니다.</p>\n<p>밝고 건강하게 자라나는 우리 패스파인더 대원들을 위해 성도님들의 많은 기도와 격려 부탁드립니다.</p>\n    <p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-53-001.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-53 001.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-53-002.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-53 002.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-53-003.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-53 003.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-54-004.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-54 004.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-54-005.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-54 005.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-55-006.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-55 006.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-55-007.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-55 007.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-56-008.jpeg\" alt=\"KakaoTalk_Photo_2026-03-14-16-55-56 008.jpeg\" style=\"height:auto;\" /></p>','20260314094318','20260314094318',9,0,0,0,0,'wp-content/uploads/2026/03/1773481398_KakaoTalk_Photo_2026-03-14-16-55-53-001.jpeg','1773481398_KakaoTalk_Photo_2026-03-14-16-55-53-001.jpeg','','','','','','','','1','',''),(28,2,0,1,'관리자','2026.3.14 대심방 (김재신 장로님, 조광현 집사님 가정)','<p>2026년 3월 14일 안식일 오후, 하나님의 은혜 가운데 대심방을 다녀왔습니다.</p>\n<p>이번 대심방에서는 김재신 장로님 댁과 조광현 집사님 댁을 방문하여 성도님들과 함께 말씀을 나누고 예배를 드리며, 귀한 교제의 시간을 가졌습니다.</p>\n<p>각 가정마다 주님의 평강과 사랑이 온전히 거하길 소망하며 축복 기도를 올렸습니다.</p>\n<p>믿음의 반석 위에 굳게 서는 귀한 가정들이 되기를 기원합니다.</p>\n    <p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481399_%EA%B9%80%EC%9E%AC%EC%8B%A0-%EC%9E%A5%EB%A1%9C%EB%8B%98%EB%8C%81.jpeg\" alt=\"김재신 장로님댁.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481399_%EA%B9%80%EC%9E%AC%EC%8B%A0-%EC%9E%A5%EB%A1%9C%EB%8B%98%EB%8C%81-2.jpeg\" alt=\"김재신 장로님댁 2.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481399_%EC%A1%B0%EA%B4%91%ED%98%84-%EC%A7%91%EC%82%AC%EB%8B%98%EB%8C%81.jpeg\" alt=\"조광현 집사님댁.jpeg\" style=\"height:auto;\" /></p><p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773481399_%EC%A1%B0%EA%B4%91%ED%98%84-%EC%A7%91%EC%82%AC%EB%8B%98%EB%8C%81-2.jpeg\" alt=\"조광현 집사님댁 2.jpeg\" style=\"height:auto;\" /></p>','20260314094319','20260314094319',11,0,0,0,0,'wp-content/uploads/2026/03/1773481399_김재신-장로님댁.jpeg','1773481399_김재신-장로님댁.jpeg','','','','','','','','1','',''),(33,4,0,1,'관리자','2026년 3월 14일 주보 (1기 11째 안식일)','<h3>📋 안식일학교 (오전 9:30)</h3>\n<p><strong>진행:</strong> 이진희  |  <strong>기도:</strong> 최원태</p>\n<p><strong>찬미:</strong> 71장  |  <strong>교과:</strong> 11과) 그리스도와 함께 사는 삶 (빌립보서 &amp; 골로새서)</p>\n<p><strong>기억절 (골3:14):</strong> \"이 모든 것 위에 사랑을 더하라 이는 온전하게 매는 띠니라\"</p>\n<hr />\n<h3>⛪ 안식일 예배 (오전 11:00)</h3>\n<p><strong>인도:</strong> 신영빈  |  <strong>기도:</strong> 최원태</p>\n<p><strong>교독문:</strong> 825번 (요15:15-17, 딤전6:7-10)</p>\n<p><strong>찬미:</strong> 24장  |  <strong>헌금찬미:</strong> 84장  |  <strong>파송찬미:</strong> 215장</p>\n<p><strong>말씀:</strong> \"서로 세우라\" (민 14:19)</p>\n<hr />\n<h3>📢 교회소식 및 안내</h3>\n<ul>\n<li>안식일학교 정각출석 캠페인: 추정선물</li>\n<li>안식일예배시간 찬양찬신 → 신정은 / 김지혜 집사에게 요청</li>\n<li>도르가 평일나눔 활동에 많은 관심과 응원 부탁</li>\n<li>2026년도 사업계획서 각 가정당 1부씩</li>\n<li>구도자 장마당 소그룹 개시: 3월중 추후공지</li>\n<li>3~5월 대심방 일정 안내</li>\n<li>품인생학교 리더교육: 3.21토~22일, 재림연수원</li>\n<li>예언세미나: 3.27금~28토</li>\n<li>선교부 매주 안식일 오후 소그룹 나눔 활동 안내</li>\n</ul>\n<hr />\n<h3>🙏 기도요청</h3>\n<ol>\n<li>건강의 어려움을 겪는 분들의 회복을 위하여</li>\n<li>권용복 집사님, 최소영 집사님 가정을 위하여</li>\n<li>가평교회 전세대의 강건한 선교사업을 위하여</li>\n<li>드림스타 후원자 / 가평지역청년 후원자</li>\n<li>재림군인 윤민영, 문은성</li>\n<li>교회와 한국 지도자, 국가(세계)정세 안정을 위하여</li>\n</ol>\n    <p><img src=\"http://gpchurch.mycafe24.com/wp-content/uploads/2026/03/1773482927_bulletin-2026-03-14.png\" alt=\"bulletin-2026-03-14.png\" style=\"height:auto;\" /></p>','20260314100847','20260314100847',5,0,0,0,0,'wp-content/uploads/2026/03/1773482927_bulletin-2026-03-14.png','1773482927_bulletin-2026-03-14.png','','','','','','','','1','',''),(34,3,0,0,'윤준석','테스트 긴 일정','<p>테스트 긴일정</p>','20260321072222','20260321083035',1,0,0,0,0,'','','','','','','','','','1','trash','1234'),(35,3,0,1,'가평교회','테스트 - 교회일정 안내','이것은 테스트 글입니다. 교회일정 게시판 기능을 확인하기 위해 작성되었습니다.','20260321074202','20260321083044',2,0,0,0,0,'','','','','','','','','','1','trash',''),(36,1,0,1,'가평교회','3월 3주차 가평안식일 교회 소식을 알려드립니다.','1. 주요 소식 및 안내\n\n정시출석 캠페인: 정시 출석 시 추첨을 통해 선물을 드립니다.\n\n특창 신청: 안식일 예배 특창 희망자는 김지혜 집사에게 문의해 주세요.\n\n도르가 행복나눔: 활동을 위한 성도님들의 많은 관심과 후원 바랍니다.\n\n선교부 소그룹 나눔: 매주 안식일 오후 1시~4시, 1층 TV 방송실에서 진행됩니다.\n\n\n2. 주요 행사 및 교육 일정\n\n손님초청 및 사랑무료나눔 안식일: 4월 4일(토) 오전 10:30 (예배, 점심식사, 무료나눔 바자회 등)\n\n예언세미나: 3월 27일(금) ~ 28일(토), 강사: 송을섭 목사\n\n교회 대청소: 4월 5일(일)\n\n창조과학 특별주말부흥회: 4월 10일(금) ~ 11일(토), 강사: 이규봉 교수\n\n집사회 봄소풍: 4월 26일(일), 진사리\n\n교회 야외예배: 5월 9일(토), 경반리 야외공연장\n\n\n3. 다음 주(3/27~28) 예배 및 봉사 안내\n\n금요예배(3/27): 인도 김지혜, 기도 김재신\n\n안식일예배(3/28): 인도 위수민, 기도 신영빈, 어린이말씀 하경자, 설교 담임목사\n\n시무 및 시무집사: 신영빈 / 허주현, 최영숙\n\n식사봉사: 이은화, 최경숙\n\n청소봉사: 집사회\n\n\n4. 기도 요청\n\n투병 중인 성도님들의 쾌유와 교회의 각종 선교 사업, 국가와 위정자들을 위해 함께 기도해 주시기 바랍니다.','20260321074709','20260321074905',21,0,0,0,0,'','','','','','','','','','1','',''),(37,3,0,1,'가평교회','신임장로 안수식 (심재영, 신영빈)','<p>신임장로 안수식 (심재영, 신영빈) 장소: 가평교회</p>','20260321075940','20260321075940',3,0,0,0,0,'','','','','','','','','','1','',''),(38,3,0,1,'가평교회','가평교회 사경회 (설악교회와 교환 설교)','가평교회 사경회 (설악교회와 교환 설교)\n장소: 가평교회','20260321080819','20260321080819',6,0,0,0,0,'','','','','','','','','','1','',''),(39,3,0,1,'가평교회','영혼구원 및 안교교사 헌신 서약일','장소: 가평교회','20260321082508','20260321082508',4,0,0,0,0,'','','','','','','','','','1','',''),(40,3,0,1,'가평교회','안식일 &amp; 청지기 준수 서약일','장소: 가평교회','20260321082510','20260321082510',3,0,0,0,0,'','','','','','','','','','1','',''),(41,3,0,1,'가평교회','행정위원회(인사)','주관: 총무부(합), 장소: 합회','20260321082512','20260321082512',2,0,0,0,0,'','','','','','','','','','1','',''),(42,3,0,1,'가평교회','전임목회자 이종식 목사 은퇴예배','장소: 가평교회','20260321082514','20260321082514',3,0,0,0,0,'','','','','','','','','','1','',''),(43,3,0,1,'가평교회','가평교회 사경회 (설악교회와 교환 설교) 2차','장소: 가평교회','20260321082516','20260321082516',3,0,0,0,0,'','','','','','','','','','1','',''),(44,3,0,1,'가평교회','(신임) 장로 &amp; 집사 줌교육 (12주)','주관: 선교부(합), 장소: 합회 (매주 금요일)','20260321082519','20260321082519',4,0,0,0,0,'','','','','','','','','','1','',''),(45,3,0,1,'가평교회','청년 회장단 연합 협의회','주관: 청소년부(합), 장소: 비전센터','20260321082520','20260321082520',4,0,0,0,0,'','','','','','','','','','1','',''),(46,3,0,1,'가평교회','목회자 AI 활용교육','주관: 디지털(합), 장소: 보건대학','20260321082523','20260321082523',4,0,0,0,0,'','','','','','','','','','1','',''),(47,3,0,1,'가평교회','전국 평신도 지도자 신학','주관: 목회부(합), 장소: 마달피수련회','20260321082525','20260321082525',5,0,0,0,0,'','','','','','','','','','1','',''),(48,3,0,1,'가평교회','전반기 목회자 협의회','주관: 목회부(합), 장소: 속초','20260321082527','20260321082527',4,0,0,0,0,'','','','','','','','','','1','',''),(49,3,0,1,'가평교회','AM선교사 발대식 및 파송식','주관: 청소년부(연), 장소: 미정','20260321082530','20260321082530',3,0,0,0,0,'','','','','','','','','','1','',''),(50,3,0,1,'가평교회','행정위원회(인사) 3월','주관: 총무부(합), 장소: 합회','20260321082533','20260321082533',2,0,0,0,0,'','','','','','','','','','1','',''),(51,3,0,1,'가평교회','렘넌트 쉐마 천연계 탐사 1차','주관: 어린이(합), 장소: 원주하늘숲','20260321082535','20260321082535',3,0,0,0,0,'','','','','','','','','','1','',''),(52,3,0,1,'가평교회','세계 청년의 날 기념 안식일','주관: 청소년(연), 