','22-revision-v1','','','2026-01-06 09:22:03','2026-01-06 09:22:03','',22,'https://gpchurch.mycafe24.com/?p=23',0,'revision','',0),(34,1,'2026-01-10 06:44:21','2026-01-10 06:44:21','<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">가평교회에 오신 것을 환영합니다</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>하나님의 사랑과 은혜가 넘치는 곳</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">예배 시간 안내</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>안식일 예배: 매주 토요일 오전 11:00 (본당 2층)</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>안식일학교: 매주 토요일 오전 9:30</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>수요 기도회: 매주 수요일 오후 7:30</p>\n<!-- /wp:paragraph -->','메인페이지','','inherit','closed','closed','','7-revision-v1','','','2026-01-10 06:44:21','2026-01-10 06:44:21','',7,'https://gpchurch.mycafe24.com/?p=34',0,'revision','',0),(35,1,'2026-01-10 06:49:15','2026-01-10 06:49:15','<!-- wp:shortcode -->\n[wpmem_form login]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','로그인 화면','','publish','closed','closed','','%eb%a1%9c%ea%b7%b8%ec%9d%b8-%ed%99%94%eb%a9%b4','','','2026-01-10 06:54:12','2026-01-10 06:54:12','',0,'https://gpchurch.mycafe24.com/?page_id=35',0,'page','',0),(36,1,'2026-01-10 06:49:15','2026-01-10 06:49:15','','로그인 화면','','inherit','closed','closed','','35-revision-v1','','','2026-01-10 06:49:15','2026-01-10 06:49:15','',35,'https://gpchurch.mycafe24.com/?p=36',0,'revision','',0),(37,1,'2026-01-10 06:49:36','2026-01-10 06:49:36','<!-- wp:site-title {\"textAlign\":\"center\"} /-->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">가평교회 교적 등록을 위한 정보를 입력해주세요.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->\n[wpmem_form register]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','회원가입 페이지','','publish','closed','closed','','%ed%9a%8c%ec%9b%90%ea%b0%80%ec%9e%85','','','2026-01-16 14:25:36','2026-01-16 14:25:36','',0,'https://gpchurch.mycafe24.com/?page_id=37',0,'page','',0),(38,1,'2026-01-10 06:49:36','2026-01-10 06:49:36','','회원가입','','inherit','closed','closed','','37-revision-v1','','','2026-01-10 06:49:36','2026-01-10 06:49:36','',37,'https://gpchurch.mycafe24.com/?p=38',0,'revision','',0),(39,1,'2026-01-10 06:49:54','2026-01-10 06:49:54','<!-- wp:shortcode -->\n[wpmem_profile]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','마이페이지','','publish','closed','closed','','%eb%a7%88%ec%9d%b4%ed%8e%98%ec%9d%b4%ec%a7%80','','','2026-01-10 07:11:56','2026-01-10 07:11:56','',0,'https://gpchurch.mycafe24.com/?page_id=39',0,'page','',0),(40,1,'2026-01-10 06:49:54','2026-01-10 06:49:54','','마이페이지','','inherit','closed','closed','','39-revision-v1','','','2026-01-10 06:49:54','2026-01-10 06:49:54','',39,'https://gpchurch.mycafe24.com/?p=40',0,'revision','',0),(41,1,'2026-01-10 06:53:09','2026-01-10 06:53:09','<!-- wp:paragraph -->\n<p>[wpmem_form login]</p>\n<!-- /wp:paragraph -->','로그인 화면','','inherit','closed','closed','','35-revision-v1','','','2026-01-10 06:53:09','2026-01-10 06:53:09','',35,'https://gpchurch.mycafe24.com/?p=41',0,'revision','',0),(42,1,'2026-01-10 06:53:48','2026-01-10 06:53:48','<!-- wp:shortcode -->\n[wpmem_form login]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','로그인 화면','','inherit','closed','closed','','35-revision-v1','','','2026-01-10 06:53:48','2026-01-10 06:53:48','',35,'https://gpchurch.mycafe24.com/?p=42',0,'revision','',0),(43,1,'2026-01-10 07:05:22','2026-01-10 07:05:22','<!-- wp:shortcode -->\n[wpmem_form register]\n<!-- /wp:shortcode -->','회원가입','','inherit','closed','closed','','37-revision-v1','','','2026-01-10 07:05:22','2026-01-10 07:05:22','',37,'https://gpchurch.mycafe24.com/?p=43',0,'revision','',0),(44,1,'2026-01-10 07:08:29','2026-01-10 07:08:29','<!-- wp:shortcode -->\n[wpmem_profile]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','마이페이지','','inherit','closed','closed','','39-revision-v1','','','2026-01-10 07:08:29','2026-01-10 07:08:29','',39,'https://gpchurch.mycafe24.com/?p=44',0,'revision','',0),(46,1,'2026-01-10 07:23:03','2026-01-10 07:23:03','\n<!-- wp:heading {\"level\":1} -->\n<h1>담임목사 인사말</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>사랑하는 성도 여러분과 이 홈페이지를 방문하신 모든 분들께 하나님의 평강을 전합니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>가평교회는 복음의 진리를 굳게 붙잡고 하나님의 사랑을 이 땅에 전하기 위해 세워진 교회입니다. 우리는 성경 말씀을 기초로 하여 예배와 교제, 봉사를 통해 하나님 나라를 이루어가고 있습니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>교회는 단순히 건물이 아닙니다. 교회는 함께 모여 하나님을 예배하고, 서로 사랑하며, 세상을 향해 빛과 소금의 역할을 감당하는 사람들입니다. 가평교회는 이러한 사명을 감당하기 위해 최선을 다하고 있습니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>우리 교회를 방문하시는 모든 분들을 진심으로 환영하며, 함께 신앙의 여정을 걸어가기를 소망합니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>주님의 은혜가 함께 하시기를 기도합니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>가평교회 담임목사 드림</strong></p>\n<!-- /wp:paragraph -->\n','인사말','','publish','closed','closed','','greeting','','','2026-03-14 08:06:14','2026-03-14 08:06:14','',151,'https://gpchurch.mycafe24.com/%ec%9d%b8%ec%82%ac%eb%a7%90-2/',0,'page','',0),(47,1,'2026-01-10 07:23:04','2026-01-10 07:23:04','\n<!-- wp:heading {\"level\":1} -->\n<h1>교회 조직도</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>가평교회의 조직 구조입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>담임목사</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>교회 전체를 이끌고 영적 지도를 담당합니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>장로회</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li>제1장로</li>\n<li>제2장로</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>부서</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li><strong>선교부</strong>: 지역 및 해외 선교 활동</li>\n<li><strong>봉사부</strong>: 교회 내외 봉사 활동</li>\n<li><strong>교육부</strong>: 안식일학교 및 교육 프로그램</li>\n<li><strong>청년부</strong>: 청년 신앙 활동</li>\n</ul>\n<!-- /wp:list -->\n','조직도','','publish','closed','closed','','organization','','','2026-03-14 08:06:15','2026-03-14 08:06:15','',151,'https://gpchurch.mycafe24.com/%ec%a1%b0%ec%a7%81%eb%8f%84-2/',0,'page','',0),(48,1,'2026-01-10 07:23:05','2026-01-10 07:23:05','\n<!-- wp:heading {\"level\":1} -->\n<h1>예배 시간 안내</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>안식일 예배</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>시간:</strong> 매주 토요일 오전 11:00<br>\n<strong>장소:</strong> 본당 2층<br>\n<strong>내용:</strong> 찬송, 기도, 말씀, 헌금, 축도</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>안식일학교</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>시간:</strong> 매주 토요일 오전 9:30<br>\n<strong>장소:</strong> 각 반별 교실<br>\n<strong>내용:</strong> 연령별 성경 공부</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>수요 기도회</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>시간:</strong> 매주 수요일 오후 7:30<br>\n<strong>장소:</strong> 본당 2층<br>\n<strong>내용:</strong> 찬송, 기도, 말씀 나눔</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>모든 분들을 환영합니다!</p>\n<!-- /wp:paragraph -->\n','예배 시간 안내','','publish','closed','closed','','worship','','','2026-03-14 08:06:16','2026-03-14 08:06:16','',152,'https://gpchurch.mycafe24.com/%ec%98%88%eb%b0%b0-%ec%8b%9c%ea%b0%84-%ec%95%88%eb%82%b4/',0,'page','',0),(49,1,'2026-01-10 07:23:05','2026-01-10 07:23:05','\n<!-- wp:heading {\"level\":1} -->\n<h1>안식일학교</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>안식일학교는 연령별로 나누어진 성경 공부 시간입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>시간표</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>매주 토요일 오전 9:30 - 10:30</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>반별 구성</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li><strong>유치부:</strong> 5-7세</li>\n<li><strong>유년부:</strong> 초등 1-3학년</li>\n<li><strong>소년부:</strong> 초등 4-6학년</li>\n<li><strong>청소년부:</strong> 중고등학생</li>\n<li><strong>청년부:</strong> 대학생 및 청년</li>\n<li><strong>장년부:</strong> 성인</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>각 반마다 교사가 배치되어 연령에 맞는 성경 공부를 진행합니다.</p>\n<!-- /wp:paragraph -->\n','안식일학교','','publish','closed','closed','','sabbath','','','2026-03-14 08:06:17','2026-03-14 08:06:17','',152,'https://gpchurch.mycafe24.com/%ec%95%88%ec%8b%9d%ec%9d%bc%ed%95%99%ea%b5%90/',0,'page','',0),(50,1,'2026-01-10 07:23:06','2026-01-10 07:23:06','\n<!-- wp:heading {\"level\":1} -->\n<h1>패스파인더</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>패스파인더는 청소년들을 위한 신앙 활동 프로그램입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>활동 내용</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li>야외 활동 및 캠핑</li>\n<li>봉사 활동</li>\n<li>성경 공부</li>\n<li>리더십 교육</li>\n<li>각종 기능 습득 (응급처치, 야외 생존 등)</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>모임 시간</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>매주 토요일 오후 3:00</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>체계적인 프로그램을 통해 청소년들의 영적, 신체적, 정신적 성장을 돕습니다.</p>\n<!-- /wp:paragraph -->\n','패스파인더','','publish','closed','closed','','pathfinder','','','2026-03-14 08:06:17','2026-03-14 08:06:17','',152,'https://gpchurch.mycafe24.com/%ed%8c%a8%ec%8a%a4%ed%8c%8c%ec%9d%b8%eb%8d%94/',0,'page','',0),(51,1,'2026-01-10 07:23:07','2026-01-10 07:23:07','\n<!-- wp:heading {\"level\":1} -->\n<h1>청년반</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>청년반은 대학생 및 청년들의 신앙과 교제를 위한 모임입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>정기 모임</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>매주 토요일 안식일학교</strong><br>\n성경 공부 및 토론</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>주요 활동</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li>성경 공부 및 신앙 토론</li>\n<li>찬양 연습 및 팀 활동</li>\n<li>봉사 활동</li>\n<li>청년 수련회 (연 1-2회)</li>\n<li>친교 활동</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>함께 신앙을 나누고 성장하는 청년 공동체입니다.</p>\n<!-- /wp:paragraph -->\n','청년반 활동','','publish','closed','closed','','youth','','','2026-03-14 08:06:18','2026-03-14 08:06:18','',152,'https://gpchurch.mycafe24.com/%ec%b2%ad%eb%85%84%eb%b0%98-%ed%99%9c%eb%8f%99/',0,'page','',0),(52,1,'2026-01-10 07:23:07','2026-01-10 07:23:07','\n<!-- wp:heading {\"level\":1} -->\n<h1>소그룹 모임</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>소그룹은 가정에서 모여 성경을 공부하고 기도하는 작은 교회입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>소그룹의 목적</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li>깊이 있는 성경 공부</li>\n<li>서로를 위한 기도</li>\n<li>친밀한 교제</li>\n<li>삶의 나눔</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>모임 방식</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>각 소그룹은 5-10명의 성도들로 구성되며, 매주 정해진 요일에 가정에서 모입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>소그룹에 참여하기 원하시는 분은 교회 사무실로 문의해 주세요.</p>\n<!-- /wp:paragraph -->\n','소그룹 모임','','publish','closed','closed','','smallgroup','','','2026-03-14 08:06:19','2026-03-14 08:06:19','',152,'https://gpchurch.mycafe24.com/%ec%86%8c%ea%b7%b8%eb%a3%b9-%eb%aa%a8%ec%9e%84/',0,'page','',0),(53,1,'2026-01-10 07:23:08','2026-01-10 07:23:08','\n<!-- wp:heading {\"level\":1} -->\n<h1>선교부</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>선교부는 복음을 전하고 하나님의 사랑을 실천하는 부서입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>주요 활동</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li><strong>지역 선교:</strong> 가평 지역 복음 전도</li>\n<li><strong>해외 선교:</strong> 선교지 파송 및 후원</li>\n<li><strong>문서 선교:</strong> 성경 책자 및 자료 배포</li>\n<li><strong>의료 선교:</strong> 무료 진료 및 건강 강좌</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>선교 활동에 참여하기 원하시는 분은 언제든지 연락 주세요.</p>\n<!-- /wp:paragraph -->\n','선교부','','trash','closed','closed','','mission__trashed','','','2026-04-26 03:55:37','2026-04-26 03:55:37','',153,'https://gpchurch.mycafe24.com/%ec%84%a0%ea%b5%90%eb%b6%80/',0,'page','',0),(54,1,'2026-01-10 07:23:09','2026-01-10 07:23:09','\n<!-- wp:heading {\"level\":1} -->\n<h1>봉사부</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>봉사부는 교회 내외의 봉사 활동을 담당하는 부서입니다.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2} -->\n<h2>주요 활동</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul>\n<li><strong>교회 내 봉사:</strong> 예배 준비, 청소, 식사 준비</li>\n<li><strong>지역 사회 봉사:</strong> 독거노인 돌봄, 환경 정화</li>\n<li><strong>재난 구호:</strong> 긴급 구호 활동</li>\n<li><strong>사랑의 나눔:</strong> 이웃 돕기 활동</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>작은 손길이 큰 사랑이 됩니다. 함께 봉사해요!</p>\n<!-- /wp:paragraph -->\n','봉사부','','trash','closed','closed','','service__trashed','','','2026-04-26 03:55:37','2026-04-26 03:55:37','',153,'https://gpchurch.mycafe24.com/%eb%b4%89%ec%82%ac%eb%b6%80/',0,'page','',0),(55,1,'2026-01-10 07:23:10','2026-01-10 07:23:10','','공지사항','','publish','closed','closed','','notices','','','2026-03-21 07:47:35','2026-03-21 07:47:35','',154,'https://gpchurch.mycafe24.com/%ea%b3%b5%ec%a7%80%ec%82%ac%ed%95%ad/',0,'page','',0),(56,1,'2026-01-10 07:23:10','2026-01-10 07:23:10','<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">갤러리</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','갤러리','','publish','closed','closed','','gallery','','','2026-04-25 08:15:10','2026-04-25 08:15:10','',154,'https://gpchurch.mycafe24.com/%ea%b0%a4%eb%9f%ac%eb%a6%ac/',0,'page','',0),(57,1,'2026-01-10 07:23:11','2026-01-10 07:23:11','<!-- wp:shortcode -->\n[ninja_form id=4]\n<!-- /wp:shortcode -->','문의/상담','','publish','closed','closed','','contact','','','2026-03-14 08:10:53','2026-03-14 08:10:53','',154,'https://gpchurch.mycafe24.com/%eb%ac%b8%ec%9d%98-%ec%83%81%eb%8b%b4/',0,'page','',0),(58,1,'2026-01-10 07:23:12','2026-01-10 07:23:12','<!-- wp:shortcode -->\n[ninja_form id=3]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','기도요청','','publish','closed','closed','','prayer','','','2026-03-