16 14:23:18','2026-01-16 14:23:18','',37,'https://gpchurch.mycafe24.com/?p=100',0,'revision','',0),(102,1,'2026-01-16 14:25:21','2026-01-16 14:25:21','<!-- wp:site-title {\"textAlign\":\"center\"} /-->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">가평교회 교적 등록을 위한 정보를 입력해주세요.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->\n[wpmem_form register]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','회원가입 페이지','','inherit','closed','closed','','37-revision-v1','','','2026-01-16 14:25:21','2026-01-16 14:25:21','',37,'https://gpchurch.mycafe24.com/?p=102',0,'revision','',0),(105,1,'2026-01-17 07:31:13','2026-01-17 07:31:13','','ktheme_child','','publish','closed','closed','','ktheme_child','','','2026-02-07 05:46:33','2026-02-07 05:46:33','',0,'https://gpchurch.mycafe24.com/ktheme_child/',0,'custom_css','',0),(106,1,'2026-01-17 07:31:13','2026-01-17 07:31:13','/* =========================================\n   1. 전체 컨테이너 디자인 (흰색 박스 카드)\n   ========================================= */\n/* 배경 및 중앙 정렬 */\n#wpmem_reg {\n    max-width: 700px;\n    margin: 50px auto;\n    background-color: #ffffff;\n    padding: 40px;\n    border-radius: 12px;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.05);\n    border: 1px solid #eaeaea;\n}\n\n/* 제목 등 불필요한 요소 숨김 (필요시 삭제) */\n#wpmem_reg legend { display: none; }\n.req-text { display: none; }\n\n/* =========================================\n   2. 입력 필드 디자인 (인풋 박스 스타일)\n   ========================================= */\n/* 입력창 모양 */\n#wpmem_reg input[type=\"text\"],\n#wpmem_reg input[type=\"password\"],\n#wpmem_reg input[type=\"email\"],\n#wpmem_reg input[type=\"tel\"],\n#wpmem_reg input[type=\"date\"],\n#wpmem_reg select,\n#wpmem_reg textarea {\n    width: 100%;\n    padding: 12px 15px;\n    border: 1px solid #ddd;\n    border-radius: 6px;\n    font-size: 14px;\n    background-color: #fff;\n    box-sizing: border-box;\n    transition: all 0.2s;\n    height: 48px; /* 높이 통일 */\n}\n\n/* 입력창 포커스 시 효과 */\n#wpmem_reg input:focus,\n#wpmem_reg select:focus {\n    border-color: #333;\n    outline: none;\n    box-shadow: 0 0 0 2px rgba(0,0,0,0.1);\n}\n\n/* 라벨(항목 이름) 스타일 */\n#wpmem_reg label.text, \n#wpmem_reg label.textarea, \n#wpmem_reg label.select {\n    display: block;\n    font-weight: 700;\n    font-size: 13px;\n    color: #333;\n    margin-bottom: 8px;\n    margin-top: 5px;\n}\n\n/* 필수 항목 별표(*) 빨간색 */\n#wpmem_reg .req {\n    color: #e74c3c;\n    margin-left: 3px;\n}\n\n/* =========================================\n   3. 그리드 레이아웃 (2단 분리 핵심 코드)\n   ========================================= */\n#wpmem_reg fieldset {\n    display: grid;\n    grid-template-columns: 1fr 1fr; /* 1:1 비율로 2개 컬럼 생성 */\n    column-gap: 20px; /* 좌우 간격 */\n    row-gap: 5px; /* 상하 간격 */\n    border: none;\n    padding: 0;\n    margin: 0;\n}\n\n/* 기본적으로 모든 요소는 한 칸을 차지하도록 설정 */\n#wpmem_reg label,\n#wpmem_reg .div_text,\n#wpmem_reg .div_textarea,\n#wpmem_reg .div_select {\n    grid-column: span 1; \n}\n\n/* -------------------------------------------\n   필드별 위치 강제 지정 (이미지 레이아웃 구현)\n   *주의: ID가 다르면 작동하지 않습니다. 확인 필요\n   ------------------------------------------- */\n\n/* [Row 1] 이메일(아이디) : 왼쪽 */\nlabel[for=\"username\"]   { grid-column: 1; grid-row: 1; }\ndiv:has(#username)      { grid-column: 1; grid-row: 2; }\n\n/* [Row 1] 비밀번호 : 오른쪽 */\nlabel[for=\"password\"]   { grid-column: 2; grid-row: 1; }\ndiv:has(#password)      { grid-column: 2; grid-row: 2; }\n\n/* [Row 2] 비밀번호 확인 : 꽉 찬 한 줄 */\nlabel[for=\"confirm_password\"] { grid-column: 1 / -1; grid-row: 3; }\ndiv:has(#confirm_password)    { grid-column: 1 / -1; grid-row: 4; }\n\n/* --- 구분선: 개인 신상 정보 (가상 요소로 추가) --- */\nlabel[for=\"kor_name\"]::before {\n    content: \"개인 신상 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%; /* 2단 전체 너비 */\n    padding-bottom: 10px;\n}\nlabel[for=\"kor_name\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"birth_date\"] { margin-top: 50px !important; }\n\n/* [Row 3] 이름 : 왼쪽 */\nlabel[for=\"kor_name\"]   { grid-column: 1; grid-row: 5; }\ndiv:has(#kor_name)      { grid-column: 1; grid-row: 6; }\n\n/* [Row 3] 생년월일 : 오른쪽 */\nlabel[for=\"birth_date\"] { grid-column: 2; grid-row: 5; }\ndiv:has(#birth_date)    { grid-column: 2; grid-row: 6; }\n\n/* [Row 4] 휴대전화 : 왼쪽 */\nlabel[for=\"billing_phone\"] { grid-column: 1; grid-row: 7; }\ndiv:has(#billing_phone)    { grid-column: 1; grid-row: 8; }\n\n/* [Row 4] 주소 : 오른쪽 */\nlabel[for=\"addr_road\"]  { grid-column: 2; grid-row: 7; }\ndiv:has(#addr_road)     { grid-column: 2; grid-row: 8; }\n\n/* [Row 5] 가족 관계 : 꽉 찬 한 줄 */\nlabel[for=\"family_rel\"] { grid-column: 1 / -1; grid-row: 9; }\ndiv:has(#family_rel)    { grid-column: 1 / -1; grid-row: 10; }\n\n/* --- 구분선: 교회 활동 정보 --- */\nlabel[for=\"church_role\"]::before {\n    content: \"교회 활동 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%;\n    padding-bottom: 10px;\n}\nlabel[for=\"church_role\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"small_group\"] { margin-top: 50px !important; }\n\n\n/* [Row 6] 교회 직분 : 왼쪽 */\nlabel[for=\"church_role\"] { grid-column: 1; grid-row: 11; }\ndiv:has(#church_role)    { grid-column: 1; grid-row: 12; }\n\n/* [Row 6] 소속 그룹 : 오른쪽 */\nlabel[for=\"small_group\"] { grid-column: 2; grid-row: 11; }\ndiv:has(#small_group)    { grid-column: 2; grid-row: 12; }\n\n/* [Row 7] 교적 구분 : 꽉 찬 한 줄 */\nlabel[for=\"member_type\"] { grid-column: 1 / -1; grid-row: 13; }\ndiv:has(#member_type)    { grid-column: 1 / -1; grid-row: 14; }\n\n/* [Row 8] 약관 동의 등 하단 버튼 영역 */\n.button_div {\n    grid-column: 1 / -1;\n    grid-row: 15;\n    text-align: center;\n    margin-top: 30px;\n}\n\n/* 버튼 디자인 */\n#wpmem_reg input[type=\"submit\"] {\n    background-color: #333; /* 버튼 색상 */\n    color: #fff;\n    border: none;\n    padding: 0 40px;\n    font-weight: bold;\n    font-size: 16px;\n    cursor: pointer;\n    width: 100%; /* 버튼 꽉 차게 */\n    height: 54px;\n}\n#wpmem_reg input[type=\"submit\"]:hover {\n    background-color: #000;\n}\n\n/* =========================================\n   4. 모바일 대응 (화면 작을 땐 1단으로)\n   ========================================= */\n@media (max-width: 600px) {\n    #wpmem_reg fieldset {\n        grid-template-columns: 1fr; /* 1단으로 변경 */\n    }\n    /* 가상요소 너비 조정 */\n    label[for=\"kor_name\"]::before,\n    label[for=\"church_role\"]::before {\n        width: 100%; \n    }\n    /* 그리드 위치 초기화 (순서대로 쌓이게) */\n    #wpmem_reg label,\n    #wpmem_reg div {\n        grid-column: 1 / -1 !important;\n        grid-row: auto !important;\n        margin-top: 0 !important;\n    }\n    /* 구분선 여백 다시 줌 */\n    label[for=\"kor_name\"], label[for=\"church_role\"] {\n        margin-top: 50px !important;\n    }\n}','ktheme_child','','inherit','closed','closed','','105-revision-v1','','','2026-01-17 07:31:13','2026-01-17 07:31:13','',105,'https://gpchurch.mycafe24.com/?p=106',0,'revision','',0),(108,1,'2026-01-17 08:18:09','2026-01-17 08:18:09','/* =========================================\n   1. 전체 컨테이너 디자인 (흰색 박스 카드)\n   ========================================= */\n/* 배경 및 중앙 정렬 */\n#wpmem_reg {\n    max-width: 700px;\n    margin: 50px auto;\n    background-color: #ffffff;\n    padding: 40px;\n    border-radius: 12px;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.05);\n    border: 1px solid #eaeaea;\n}\n\n/* 제목 등 불필요한 요소 숨김 (필요시 삭제) */\n#wpmem_reg legend { display: none; }\n.req-text { display: none; }\n\n/* =========================================\n   2. 입력 필드 디자인 (인풋 박스 스타일)\n   ========================================= */\n/* 입력창 모양 */\n#wpmem_reg input[type=\"text\"],\n#wpmem_reg input[type=\"password\"],\n#wpmem_reg input[type=\"email\"],\n#wpmem_reg input[type=\"tel\"],\n#wpmem_reg input[type=\"date\"],\n#wpmem_reg select,\n#wpmem_reg textarea {\n    width: 100%;\n    padding: 12px 15px;\n    border: 1px solid #ddd;\n    border-radius: 6px;\n    font-size: 14px;\n    background-color: #fff;\n    box-sizing: border-box;\n    transition: all 0.2s;\n    height: 48px; /* 높이 통일 */\n}\n\n/* 입력창 포커스 시 효과 */\n#wpmem_reg input:focus,\n#wpmem_reg select:focus {\n    border-color: #333;\n    outline: none;\n    box-shadow: 0 0 0 2px rgba(0,0,0,0.1);\n}\n\n/* 라벨(항목 이름) 스타일 */\n#wpmem_reg label.text, \n#wpmem_reg label.textarea, \n#wpmem_reg label.select {\n    display: block;\n    font-weight: 700;\n    font-size: 13px;\n    color: #333;\n    margin-bottom: 8px;\n    margin-top: 5px;\n}\n\n/* 필수 항목 별표(*) 빨간색 */\n#wpmem_reg .req {\n    color: #e74c3c;\n    margin-left: 3px;\n}\n\n/* =========================================\n   3. 그리드 레이아웃 (2단 분리 핵심 코드)\n   ========================================= */\n#wpmem_reg fieldset {\n    display: grid;\n    grid-template-columns: 1fr 1fr; /* 1:1 비율로 2개 컬럼 생성 */\n    column-gap: 20px; /* 좌우 간격 */\n    row-gap: 5px; /* 상하 간격 */\n    border: none;\n    padding: 0;\n    margin: 0;\n}\n\n/* 기본적으로 모든 요소는 한 칸을 차지하도록 설정 */\n#wpmem_reg label,\n#wpmem_reg .div_text,\n#wpmem_reg .div_textarea,\n#wpmem_reg .div_select {\n    grid-column: span 1; \n}\n\n/* -------------------------------------------\n   필드별 위치 강제 지정 (이미지 레이아웃 구현)\n   *주의: ID가 다르면 작동하지 않습니다. 확인 필요\n   ------------------------------------------- */\n\n/* [Row 1] 이메일(아이디) : 왼쪽 */\nlabel[for=\"username\"]   { grid-column: 1; grid-row: 1; }\ndiv:has(#username)      { grid-column: 1; grid-row: 2; }\n\n/* [Row 1] 비밀번호 : 오른쪽 */\nlabel[for=\"password\"]   { grid-column: 2; grid-row: 1; }\ndiv:has(#password)      { grid-column: 2; grid-row: 2; }\n\n/* [Row 2] 비밀번호 확인 : 꽉 찬 한 줄 */\nlabel[for=\"confirm_password\"] { grid-column: 1 / -1; grid-row: 3; }\ndiv:has(#confirm_password)    { grid-column: 1 / -1; grid-row: 4; }\n\n/* --- 구분선: 개인 신상 정보 (가상 요소로 추가) --- */\nlabel[for=\"kor_name\"]::before {\n    content: \"개인 신상 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%; /* 2단 전체 너비 */\n    padding-bottom: 10px;\n}\nlabel[for=\"kor_name\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"birth_date\"] { margin-top: 50px !important; }\n\n/* [Row 3] 이름 : 왼쪽 */\nlabel[for=\"kor_name\"]   { grid-column: 1; grid-row: 5; }\ndiv:has(#kor_name)      { grid-column: 1; grid-row: 6; }\n\n/* [Row 3] 생년월일 : 오른쪽 */\nlabel[for=\"birth_date\"] { grid-column: 2; grid-row: 5; }\ndiv:has(#birth_date)    { grid-column: 2; grid-row: 6; }\n\n/* [Row 4] 휴대전화 : 왼쪽 */\nlabel[for=\"billing_phone\"] { grid-column: 1; grid-row: 7; }\ndiv:has(#billing_phone)    { grid-column: 1; grid-row: 8; }\n\n/* [Row 4] 주소 : 오른쪽 */\nlabel[for=\"addr_road\"]  { grid-column: 2; grid-row: 7; }\ndiv:has(#addr_road)     { grid-column: 2; grid-row: 8; }\n\n/* [Row 5] 가족 관계 : 꽉 찬 한 줄 */\nlabel[for=\"family_rel\"] { grid-column: 1 / -1; grid-row: 9; }\ndiv:has(#family_rel)    { grid-column: 1 / -1; grid-row: 10; }\n\n/* --- 구분선: 교회 활동 정보 --- */\nlabel[for=\"church_role\"]::before {\n    content: \"교회 활동 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%;\n    padding-bottom: 10px;\n}\nlabel[for=\"church_role\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"small_group\"] { margin-top: 50px !important; }\n\n\n/* [Row 6] 교회 직분 : 왼쪽 */\nlabel[for=\"church_role\"] { grid-column: 1; grid-row: 11; }\ndiv:has(#church_role)    { grid-column: 1; grid-row: 12; }\n\n/* [Row 6] 소속 그룹 : 오른쪽 */\nlabel[for=\"small_group\"] { grid-column: 2; grid-row: 11; }\ndiv:has(#small_group)    { grid-column: 2; grid-row: 12; }\n\n/* [Row 7] 교적 구분 : 꽉 찬 한 줄 */\nlabel[for=\"member_type\"] { grid-column: 1 / -1; grid-row: 13; }\ndiv:has(#member_type)    { grid-column: 1 / -1; grid-row: 14; }\n\n/* [Row 8] 약관 동의 등 하단 버튼 영역 */\n.button_div {\n    grid-column: 1 / -1;\n    grid-row: 15;\n    text-align: center;\n    margin-top: 30px;\n}\n\n/* 버튼 디자인 */\n#wpmem_reg input[type=\"submit\"] {\n    background-color: #333; /* 버튼 색상 */\n    color: #fff;\n    border: none;\n    padding: 0 40px;\n    font-weight: bold;\n    font-size: 16px;\n    cursor: pointer;\n    width: 100%; /* 버튼 꽉 차게 */\n    height: 54px;\n}\n#wpmem_reg input[type=\"submit\"]:hover {\n    background-color: #000;\n}\n\n/* =========================================\n   4. 모바일 대응 (화면 작을 땐 1단으로)\n   ========================================= */\n@media (max-width: 600px) {\n    #wpmem_reg fieldset {\n        grid-template-columns: 1fr; /* 1단으로 변경 */\n    }\n    /* 가상요소 너비 조정 */\n    label[for=\"kor_name\"]::before,\n    label[for=\"church_role\"]::before {\n        width: 100%; \n    }\n    /* 그리드 위치 초기화 (순서대로 쌓이게) */\n    #wpmem_reg label,\n    #wpmem_reg div {\n        grid-column: 1 / -1 !important;\n        grid-row: auto !important;\n        margin-top: 0 !important;\n    }\n    /* 구분선 여백 다시 줌 */\n    label[for=\"kor_name\"], label[for=\"church_role\"] {\n        margin-top: 50px !important;\n    }\n}\n\n/* === 로그인 폼 디자인 커스텀 === */\n\n/* 1. 입력 필드 스타일 (아이콘 공간 확보) */\n#wpmem_login input[type=\"text\"], \n#wpmem_login input[type=\"password\"] {\n    width: 100%;\n    height: 50px;\n    padding: 10px 15px 10px 45px; /* 왼쪽에 아이콘 들어갈 여백 45px 확보 */\n    border: 1px solid #ddd;\n    border-radius: 8px;\n    font-size: 15px;\n    background-color: #fff;\n    margin-bottom: 15px;\n    box-sizing: border-box;\n    /* 배경 아이콘 설정 (이미지 경로를 실제 경로로 수정하세요) */\n    background-repeat: no-repeat;\n    background-position: 15px center;\n    background-size: 20px;\n}\n\n/* 2. 아이디 입력창 아이콘 (편지 봉투) */\n#wpmem_login input[name=\"log\"] {\n    /* 예시: 구글 아이콘이나 본인 서버의 이미지 URL을 넣으세요 */\n    background-image: url(\'https://gpchurch.mycafe24.com/img/icon_email.png\'); \n}\n\n/* 3. 비밀번호 입력창 아이콘 (자물쇠) */\n#wpmem_login input[name=\"pwd\"] {\n    background-image: url(\'https://gpchurch.mycafe24.com/img/icon_lock.png\');\n}\n\n/* 4. 라벨(이메일 주소, 비밀번호 글자) 스타일 */\n#wpmem_login label {\n    display: block;\n    font-weight: bold;\n    font-size: 13px;\n    color: #333;\n    margin-bottom: 5px;\n}\n\n/* 5. 로그인 버튼 스타일 */\n#wpmem_login input[type=\"submit\"] {\n    display: none; /* 기본 버튼 숨기고 아래에서 새로 디자인하거나, 이 속성을 지우고 스타일링하세요 */\n}\n/* 버튼을 살려서 디자인하려면 위 display:none을 지우고 아래를 쓰세요 */\n#wpmem_login .button_div input[type=\"submit\"] {\n    width: 100%;\n    background-color: #007bff; /* 파란색 */\n    color: white;\n    font-weight: bold;\n    padding: 15px 0;\n    border: none;\n    border-radius: 8px;\n    cursor: pointer;\n    font-size: 16px;\n    margin-top: 10px;\n}\n\n/* 6. 로그인 상태 유지 & 비밀번호 찾기 배치 */\n#wpmem_login .div_text {\n    margin-bottom: 0; /* 간격 조정 */\n}\n/* 체크박스 영역 등 미세 조정은 개발자 도구로 id 확인 필요 */','ktheme_child','','inherit','closed','closed','','105-revision-v1','','','2026-01-17 08:18:09','2026-01-17 08:18:09','',105,'https://gpchurch.mycafe24.com/?p=108',0,'revision','',0),(112,0,'2026-01-24 06:00:23','2026-01-24 06:00:23','공지사항 테스트 입니다','테스트 입니다','','trash','closed','closed','','1__trashed','','','2026-03-21 07:48:32','2026-03-21 07:48:32','',1,'https://gpchurch.mycafe24.com/?kboard_content_redirect=1',0,'kboard','',0),(113,0,'2026-01-24 06:00:24','2026-01-24 06:00:24','','묵찌-로고.png','','inherit','open','closed','','%eb%ac%b5%ec%b0%8c-%eb%a1%9c%ea%b3%a0-png','','','2026-01-24 06:00:24','2026-01-24 06:00:24','',0,'https://gpchurch.mycafe24.com/%eb%ac%b5%ec%b0%8c-%eb%a1%9c%ea%b3%a0-png/',0,'attachment','image/png',0),(114,3,'2026-01-24 06:03:21','2026-01-24 06:03:21','데스트 입니다','로그인 후 글쓰기 테스트','','trash','closed','closed','','2__trashed','','','2026-03-21 07:48:24','2026-03-21 07:48:24','',1,'https://gpchurch.mycafe24.com/?kboard_content_redirect=2',0,'kboard','',0),(115,3,'2026-01-24 06:03:21','2026-01-24 06:03:21','','묵찌-로고.png','','inherit','open','closed','','%eb%ac%b5%ec%b0%8c-%eb%a1%9