,'','2026-03-14 08:10:51','2026-03-14 08:10:51','',2,'https://gpchurch.mycafe24.com/?kboard_content_redirect=4',0,'kboard','',0),(134,1,'2026-01-31 06:46:26','2026-01-31 06:46:26','','묵찌-로고.png','','inherit','open','closed','','%eb%ac%b5%ec%b0%8c-%eb%a1%9c%ea%b3%a0-png-4','','','2026-01-31 06:46:26','2026-01-31 06:46:26','',0,'https://gpchurch.mycafe24.com/%eb%ac%b5%ec%b0%8c-%eb%a1%9c%ea%b3%a0-png-4/',0,'attachment','image/png',0),(135,1,'2026-01-31 06:46:53','2026-01-31 06:46:53','test3','test3','','trash','closed','closed','','5__trashed','','','2026-03-14 08:10:58','2026-03-14 08:10:58','',2,'https://gpchurch.mycafe24.com/?kboard_content_redirect=5',0,'kboard','',0),(136,1,'2026-01-31 06:46:53','2026-01-31 06:46:53','','픽셀-아트-게임.jpg','','inherit','open','closed','','%ed%94%bd%ec%85%80-%ec%95%84%ed%8a%b8-%ea%b2%8c%ec%9e%84-jpg','','','2026-01-31 06:46:53','2026-01-31 06:46:53','',0,'https://gpchurch.mycafe24.com/%ed%94%bd%ec%85%80-%ec%95%84%ed%8a%b8-%ea%b2%8c%ec%9e%84-jpg/',0,'attachment','image/jpeg',0),(138,1,'2026-01-31 06:50:47','2026-01-31 06:50:47','/* =========================================\n   1. 전체 컨테이너 디자인 (흰색 박스 카드)\n   ========================================= */\n/* 배경 및 중앙 정렬 */\n#wpmem_reg {\n    max-width: 700px;\n    margin: 50px auto;\n    background-color: #ffffff;\n    padding: 40px;\n    border-radius: 12px;\n    box-shadow: 0 5px 20px rgba(0,0,0,0.05);\n    border: 1px solid #eaeaea;\n}\n\n/* 제목 등 불필요한 요소 숨김 (필요시 삭제) */\n#wpmem_reg legend { display: none; }\n.req-text { display: none; }\n\n/* =========================================\n   2. 입력 필드 디자인 (인풋 박스 스타일)\n   ========================================= */\n/* 입력창 모양 */\n#wpmem_reg input[type=\"text\"],\n#wpmem_reg input[type=\"password\"],\n#wpmem_reg input[type=\"email\"],\n#wpmem_reg input[type=\"tel\"],\n#wpmem_reg input[type=\"date\"],\n#wpmem_reg select,\n#wpmem_reg textarea {\n    width: 100%;\n    padding: 12px 15px;\n    border: 1px solid #ddd;\n    border-radius: 6px;\n    font-size: 14px;\n    background-color: #fff;\n    box-sizing: border-box;\n    transition: all 0.2s;\n    height: 48px; /* 높이 통일 */\n}\n\n/* 입력창 포커스 시 효과 */\n#wpmem_reg input:focus,\n#wpmem_reg select:focus {\n    border-color: #333;\n    outline: none;\n    box-shadow: 0 0 0 2px rgba(0,0,0,0.1);\n}\n\n/* 라벨(항목 이름) 스타일 */\n#wpmem_reg label.text, \n#wpmem_reg label.textarea, \n#wpmem_reg label.select {\n    display: block;\n    font-weight: 700;\n    font-size: 13px;\n    color: #333;\n    margin-bottom: 8px;\n    margin-top: 5px;\n}\n\n/* 필수 항목 별표(*) 빨간색 */\n#wpmem_reg .req {\n    color: #e74c3c;\n    margin-left: 3px;\n}\n\n/* =========================================\n   3. 그리드 레이아웃 (2단 분리 핵심 코드)\n   ========================================= */\n#wpmem_reg fieldset {\n    display: grid;\n    grid-template-columns: 1fr 1fr; /* 1:1 비율로 2개 컬럼 생성 */\n    column-gap: 20px; /* 좌우 간격 */\n    row-gap: 5px; /* 상하 간격 */\n    border: none;\n    padding: 0;\n    margin: 0;\n}\n\n/* 기본적으로 모든 요소는 한 칸을 차지하도록 설정 */\n#wpmem_reg label,\n#wpmem_reg .div_text,\n#wpmem_reg .div_textarea,\n#wpmem_reg .div_select {\n    grid-column: span 1; \n}\n\n/* -------------------------------------------\n   필드별 위치 강제 지정 (이미지 레이아웃 구현)\n   *주의: ID가 다르면 작동하지 않습니다. 확인 필요\n   ------------------------------------------- */\n\n/* [Row 1] 이메일(아이디) : 왼쪽 */\nlabel[for=\"username\"]   { grid-column: 1; grid-row: 1; }\ndiv:has(#username)      { grid-column: 1; grid-row: 2; }\n\n/* [Row 1] 비밀번호 : 오른쪽 */\nlabel[for=\"password\"]   { grid-column: 2; grid-row: 1; }\ndiv:has(#password)      { grid-column: 2; grid-row: 2; }\n\n/* [Row 2] 비밀번호 확인 : 꽉 찬 한 줄 */\nlabel[for=\"confirm_password\"] { grid-column: 1 / -1; grid-row: 3; }\ndiv:has(#confirm_password)    { grid-column: 1 / -1; grid-row: 4; }\n\n/* --- 구분선: 개인 신상 정보 (가상 요소로 추가) --- */\nlabel[for=\"kor_name\"]::before {\n    content: \"개인 신상 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%; /* 2단 전체 너비 */\n    padding-bottom: 10px;\n}\nlabel[for=\"kor_name\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"birth_date\"] { margin-top: 50px !important; }\n\n/* [Row 3] 이름 : 왼쪽 */\nlabel[for=\"kor_name\"]   { grid-column: 1; grid-row: 5; }\ndiv:has(#kor_name)      { grid-column: 1; grid-row: 6; }\n\n/* [Row 3] 생년월일 : 오른쪽 */\nlabel[for=\"birth_date\"] { grid-column: 2; grid-row: 5; }\ndiv:has(#birth_date)    { grid-column: 2; grid-row: 6; }\n\n/* [Row 4] 휴대전화 : 왼쪽 */\nlabel[for=\"billing_phone\"] { grid-column: 1; grid-row: 7; }\ndiv:has(#billing_phone)    { grid-column: 1; grid-row: 8; }\n\n/* [Row 4] 주소 : 오른쪽 */\nlabel[for=\"addr_road\"]  { grid-column: 2; grid-row: 7; }\ndiv:has(#addr_road)     { grid-column: 2; grid-row: 8; }\n\n/* [Row 5] 가족 관계 : 꽉 찬 한 줄 */\nlabel[for=\"family_rel\"] { grid-column: 1 / -1; grid-row: 9; }\ndiv:has(#family_rel)    { grid-column: 1 / -1; grid-row: 10; }\n\n/* --- 구분선: 교회 활동 정보 --- */\nlabel[for=\"church_role\"]::before {\n    content: \"교회 활동 정보\";\n    display: block;\n    position: absolute;\n    top: -40px;\n    left: 0;\n    font-size: 14px;\n    color: #888;\n    border-bottom: 1px solid #eee;\n    width: 200%;\n    padding-bottom: 10px;\n}\nlabel[for=\"church_role\"] { position: relative; margin-top: 50px !important; }\nlabel[for=\"small_group\"] { margin-top: 50px !important; }\n\n\n/* [Row 6] 교회 직분 : 왼쪽 */\nlabel[for=\"church_role\"] { grid-column: 1; grid-row: 11; }\ndiv:has(#church_role)    { grid-column: 1; grid-row: 12; }\n\n/* [Row 6] 소속 그룹 : 오른쪽 */\nlabel[for=\"small_group\"] { grid-column: 2; grid-row: 11; }\ndiv:has(#small_group)    { grid-column: 2; grid-row: 12; }\n\n/* [Row 7] 교적 구분 : 꽉 찬 한 줄 */\nlabel[for=\"member_type\"] { grid-column: 1 / -1; grid-row: 13; }\ndiv:has(#member_type)    { grid-column: 1 / -1; grid-row: 14; }\n\n/* [Row 8] 약관 동의 등 하단 버튼 영역 */\n.button_div {\n    grid-column: 1 / -1;\n    grid-row: 15;\n    text-align: